import { Shield, Brain, Globe, Network, Gamepad2, Database } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { glass } from '../utils/glass';

export default function About() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const bg    = dark ? '#13131e' : '#f5f0e8';
  const ink   = dark ? '#f0f0f8' : '#1a1a2e';
  const muted = dark ? 'rgba(255,255,255,0.6)' : '#5a5a72';

  // Game Modding replaces Python & C++
  const skills = [
    { Icon: Shield,   key: 'cyber' },
    { Icon: Brain,    key: 'ai' },
    { Icon: Network,  key: 'net' },
    { Icon: Globe,    key: 'web' },
    { Icon: Gamepad2, key: 'game' },   // ← changed
    { Icon: Database, key: 'db' },
  ];

  return (
    <section id="about" style={{ background: bg }} className="py-24 px-[5%] transition-colors duration-300">
      <SectionHeader tag={tr.aboutTag} title={tr.aboutTitle} />
      <div className="grid md:grid-cols-2 gap-16 items-start">

        <div className="space-y-5">
          {[tr.aboutP1, tr.aboutP2].map((p, i) => (
            <p key={i} className="reveal text-[1rem] leading-[1.9]" style={{ color: muted, transitionDelay: `${i * 0.1}s` }}>
              {p}
            </p>
          ))}

          {/* Scout badges */}
          <div className="reveal space-y-2 pt-1" style={{ transitionDelay: '0.2s' }}>
            {[
              { emoji: '🏅', text: lang === 'ar' ? 'بطل الكشافة الوطني — المركز الأول (2020)' : 'National Scout Excellence Champion — 1st Place (2020)' },
              { emoji: '🏆', text: lang === 'ar' ? 'مديرية أسيوط — المركز الأول (2019)' : '2019 · Asyut Directorate — Scout Excellence, 1st Place' },
            ].map((b, i) => (
              <div key={i} className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-xs font-semibold block"
                style={{ background: 'rgba(240,165,0,0.09)', border: '1px solid rgba(240,165,0,0.22)', color: '#e8920a', marginBottom: 6 }}>
                {b.emoji} {b.text}
              </div>
            ))}
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3">
          {skills.map(({ Icon, key }, i) => (
            <div key={key} className="reveal flex items-center gap-3 px-4 py-3.5 rounded-xl transition-all duration-250 cursor-default"
              style={{ ...glass(dark), transitionDelay: `${i * 0.06}s` }}
              onMouseEnter={e => {
                e.currentTarget.style.transform = 'translateX(5px)';
                e.currentTarget.style.borderColor = 'rgba(240,165,0,0.3)';
                e.currentTarget.style.boxShadow = '0 8px 28px rgba(240,165,0,0.12)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = 'translateX(0)';
                e.currentTarget.style.borderColor = dark ? 'rgba(255,255,255,0.10)' : 'rgba(255,255,255,0.80)';
                e.currentTarget.style.boxShadow = dark ? '0 4px 24px rgba(0,0,0,0.3)' : '0 4px 24px rgba(26,26,46,0.08)';
              }}>
              <span className="flex-shrink-0" style={{ color: '#f0a500' }}><Icon size={18} /></span>
              <span className="text-sm font-medium" style={{ color: ink }}>{tr.skills[key]}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
